            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 6,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/quality"]""",
            Tags = """["quality","qc","inspection","walkthrough"]""",
            ContentJson = """{"appRoute":"/quality","startButtonLabel":"Tour Quality","steps":[{"element":".tab-bar","popover":{"title":"Quality Tabs","description":"The Quality module has nine tabs: QC Inspections, Lot Tracking, SPC Charts, SPC Data Entry, OOC Events, NCRs, CAPAs, ECOs, and Gages. Each tab focuses on a different aspect of quality management. The active tab is reflected in the URL for bookmarking and sharing.","side":"bottom"}},{"element":".tab:nth-child(1)","popover":{"title":"QC Inspections Tab","description":"The default tab. Lists all QC inspections with date, job number, template name, inspector, lot number, status (In Progress/Passed/Failed shown as color-coded chips), and results summary (passed/total). Use the Status dropdown filter to narrow results. Click 'New Inspection' to create one.","side":"bottom"}},{"element":"[data-testid='new-inspection-btn']","popover":{"title":"New Inspection Button","description":"Opens the inspection creation dialog. Select a QC template (optional — populates checklist items), enter a Job ID, lot number, and notes. The inspector is automatically set to the current user.","side":"bottom"}},{"element":".tab:nth-child(2)","popover":{"title":"Lot Tracking Tab","description":"Tracks material lot records with lot number, part number, description, quantity, job, supplier lot, expiration date, and creation date. Search by lot or part number. Each row has a traceability button (tree icon) that opens a dialog showing every linked record: jobs, production runs, purchase orders, bin locations, and QC inspections.","side":"bottom"}},{"element":".tab:nth-child(3)","popover":{"title":"SPC Charts Tab","description":"Displays X-bar and Range control charts for SPC characteristics. Select a characteristic from the sidebar list (linked to parts and operations). The chart shows data points, control limits (UCL/LCL), spec limits (USL/LSL), center line, and highlights out-of-control points. Process capability indices (Cp, Cpk, Pp, Ppk) are displayed alongside.","side":"bottom"}},{"element":".tab:nth-child(4)","popover":{"title":"SPC Data Entry Tab","description":"Record measurement subgroups for a selected characteristic. Select a characteristic from the sidebar, then enter measurement values for each subgroup. The system calculates mean, range, standard deviation, and automatically checks for out-of-control conditions using Western Electric rules.","side":"bottom"}},{"element":".tab:nth-child(5)","popover":{"title":"OOC Events Tab","description":"Lists all out-of-control events detected by SPC analysis. Each event shows the characteristic, part, detection time, rule violated, severity (Warning/Out of Control/Out of Spec), and status (Open/Acknowledged/CAPA Created/Resolved). You can acknowledge events and create CAPAs directly from OOC events.","side":"bottom"}},{"element":".tab:nth-child(6)","popover":{"title":"NCRs Tab","description":"Non-Conformance Reports document quality failures. Lists NCR number, type (Internal/Supplier/Customer), part, affected quantity, status (Open/Under Review/Contained/Dispositioned/Closed), and cost impact. Filter by type and status. Create new NCRs or disposition existing ones (Use As Is, Rework, Scrap, Return to Vendor, Sort & Screen, Concession).","side":"bottom"}},{"element":".tab:nth-child(7)","popover":{"title":"CAPAs Tab","description":"Corrective and Preventive Actions drive systematic problem resolution. Lists CAPA number, type (Corrective/Preventive), title, status, owner, priority, due date, and task progress. CAPAs advance through phases: Identification, Containment, Root Cause Analysis, Corrective Action, Verification, Effectiveness Check.","side":"bottom"}},{"element":".tab:nth-child(8)","popover":{"title":"ECOs Tab","description":"Engineering Change Orders manage controlled changes to parts, processes, and documentation. Lists ECO number, title, change type, status (Draft/Review/Approved/In Implementation/Implemented/Cancelled), priority, and affected item count. Create, review, and track implementation of engineering changes.","side":"bottom"}},{"element":".tab:nth-child(9)","popover":{"title":"Gages Tab","description":"Manages measurement instruments and calibration schedules. Lists gage number, description, type, status (In Service/Due for Cal/Out for Cal/Out of Service/Retired), next calibration due date, and calibration record count. Click a gage row to see its full detail and calibration history. Record new calibrations with result, lab name, certificate, and as-found/as-left conditions.","side":"bottom"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Quality Field Reference",
            Slug = "quality-field-reference",
            Summary = "Complete reference for every field, button, status, validation rule, column, and action across all nine Quality tabs.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/quality"]""",
            Tags = """["quality","qc","inspection","reference"]""",
            ContentJson = """{"title":"Quality Field Reference","groups":[{"heading":"QC Template Fields","items":[{"label":"Name (required)","value":"Text input. Identifies the checklist template. Examples: 'Incoming Material Inspection', 'Final Assembly QC', 'Dimensional Check'."},{"label":"Description","value":"Text input, optional. Explains the purpose of the template or when it should be used."},{"label":"Part","value":"Entity picker, optional. Links the template to a specific part. When set, this template is suggested when inspecting that part."},{"label":"IsActive","value":"Toggle. Active templates appear in the template dropdown when creating inspections. Default: true."}]},{"heading":"QC Checklist Item Fields","items":[{"label":"Description (required)","value":"Text input. What the inspector should check. Examples: 'Surface finish within Ra 32', 'Dimension A = 2.500 +/- 0.005'."},{"label":"Specification","value":"Text input, optional. The expected value, tolerance, or pass/fail criteria. Shown alongside the check description during inspection."},{"label":"Sort Order","value":"Number input. Controls the display order of items within the template. Lower numbers appear first."},{"label":"IsRequired","value":"Toggle. When on, this check must be completed (passed or failed) before the inspection can be finalized. Default: true."}]},{"heading":"Inspection Form Fields","items":[{"label":"Template","value":"Select dropdown, optional. Choosing a template pre-populates the inspection with that template's checklist items. data-testid: inspection-template"},{"label":"Job ID","value":"Number input, optional. Links the inspection to a specific job. data-testid: inspection-job"},{"label":"Lot Number","value":"Text input, optional. Associates the inspection with a material lot for traceability. data-testid: inspection-lot"},{"label":"Notes","value":"Textarea, optional. Free-form notes about the inspection. data-testid: inspection-notes"}]},{"heading":"Inspection Result Fields","items":[{"label":"Description","value":"Text, pre-populated from checklist item. The check being performed."},{"label":"Passed","value":"Boolean (pass/fail toggle). Whether this individual check passed."},{"label":"Measured Value","value":"Text input, optional. The actual value measured during the check (e.g., '2.503', 'Ra 28')."},{"label":"Notes","value":"Text input, optional. Inspector notes for this specific check."}]},{"heading":"Inspection Statuses","items":[{"label":"In Progress (yellow chip)","value":"Inspection is actively being performed. Results are being recorded."},{"label":"Passed (green chip)","value":"All required checks passed. Inspection is complete with a passing result."},{"label":"Failed (red chip)","value":"One or more required checks failed. May trigger an NCR or hold."}]},{"heading":"Inspections Table Columns","items":[{"label":"Date","value":"Sortable. When the inspection was created. Format: MM/dd/yyyy."},{"label":"Job","value":"Sortable. The linked job number, or dash if none."},{"label":"Template","value":"Sortable. The QC template used, or dash if ad-hoc inspection."},{"label":"Inspector","value":"Sortable. Name of the person who performed the inspection."},{"label":"Lot Number","value":"Sortable. The material lot inspected, displayed in monospace font."},{"label":"Status","value":"Sortable, filterable (enum). Color-coded chip: In Progress (yellow), Passed (green), Failed (red)."},{"label":"Results Summary","value":"Center-aligned. Shows passed/total count (e.g., '5/6'). Dash if no results recorded."}]},{"heading":"Lot Record Fields","items":[{"label":"Part (required)","value":"Number input (Part ID). The part this lot is for. Validators: required."},{"label":"Quantity (required)","value":"Number input. How many units in this lot. Validators: required, min 1. Default: 1."},{"label":"Lot Number","value":"Text input, optional. If left blank, the system auto-generates a unique lot number."},{"label":"Job ID","value":"Number input, optional. Links the lot to a production job."},{"label":"Supplier Lot Number","value":"Text input, optional. The vendor's lot number for incoming material."},{"label":"Notes","value":"Textarea, optional. Notes about the lot (e.g., storage conditions, special handling)."}]},{"heading":"Lot Table Columns","items":[{"label":"Lot Number","value":"Sortable. Displayed in monospace font. Width: 160px."},{"label":"Part #","value":"Sortable. The part number associated with this lot. Width: 120px."},{"label":"Description","value":"Sortable. Part description."},{"label":"Quantity","value":"Sortable, right-aligned. Number of units in the lot. Width: 80px."},{"label":"Job","value":"Sortable. Linked job number, or dash. Width: 100px."},{"label":"Supplier Lot","value":"Sortable. Vendor's lot number, or dash. Width: 140px."},{"label":"Expires","value":"Sortable, date type. Expiration date or dash. Width: 110px."},{"label":"Created","value":"Sortable, date type. When the lot was created. Width: 110px."},{"label":"Actions","value":"Center-aligned traceability button (account_tree icon). Opens the traceability dialog. Width: 50px."}]},{"heading":"Traceability Dialog Sections","items":[{"label":"Header","value":"Shows Part number and Part description for the lot."},{"label":"Jobs","value":"Lists all jobs that used this lot — job number and title."},{"label":"Production Runs","value":"Lists linked production runs — run number and status chip."},{"label":"Purchase Orders","value":"Lists POs that supplied this material — PO number and vendor name."},{"label":"Bin Locations","value":"Shows where the material is stored — location name and quantity."},{"label":"QC Inspections","value":"Lists inspections against this lot — status chip, inspector name, and date."}]},{"heading":"SPC Characteristic Fields","items":[{"label":"Part (required)","value":"Entity picker. The part being measured."},{"label":"Operation","value":"Optional. The specific manufacturing operation where measurement occurs."},{"label":"Name (required)","value":"Text input. Characteristic name (e.g., 'Diameter A', 'Surface Roughness')."},{"label":"Description","value":"Text, optional. Additional detail about the characteristic."},{"label":"Measurement Type","value":"Select: Variable (continuous measurement) or Attribute (pass/fail). Default: Variable."},{"label":"Nominal Value (required)","value":"Number. The target/ideal measurement value."},{"label":"Upper Spec Limit (required)","value":"Number. Maximum acceptable value (USL)."},{"label":"Lower Spec Limit (required)","value":"Number. Minimum acceptable value (LSL)."},{"label":"Unit of Measure","value":"Text, optional (e.g., 'mm', 'inches', 'Ra')."},{"label":"Decimal Places","value":"Number. How many decimal places to display for measurements."},{"label":"Sample Size","value":"Number. Number of readings per subgroup (e.g., 5)."},{"label":"Sample Frequency","value":"Text, optional. How often to sample (e.g., 'Every 50 parts', 'Hourly')."},{"label":"Gage","value":"Optional. Links to a gage from the Gages tab for traceability."},{"label":"IsActive","value":"Toggle. Inactive characteristics are hidden from data entry."},{"label":"Notify on OOC","value":"Toggle. When on, generates a notification when an out-of-control condition is detected."}]},{"heading":"SPC Chart Elements","items":[{"label":"UCL (Upper Control Limit)","value":"Calculated from measurement data. Upper boundary of normal process variation."},{"label":"LCL (Lower Control Limit)","value":"Calculated from measurement data. Lower boundary of normal process variation."},{"label":"Center Line","value":"Process mean (X-bar chart) or average range (R chart)."},{"label":"USL / LSL","value":"Spec limits from the characteristic definition. Not the same as control limits."},{"label":"OOC Points","value":"Points that violate Western Electric rules are highlighted on the chart."},{"label":"Cp / Cpk","value":"Short-term process capability. Cp = potential, Cpk = actual (accounts for centering)."},{"label":"Pp / Ppk","value":"Long-term process performance. Pp = potential, Ppk = actual."}]},{"heading":"OOC Event Fields","items":[{"label":"Severity","value":"Warning (minor rule violation), Out of Control (major rule violation), Out of Spec (beyond USL/LSL)."},{"label":"Status","value":"Open (detected, not yet reviewed), Acknowledged (reviewed by quality), CAPA Created (linked to corrective action), Resolved (root cause addressed)."},{"label":"Rule Name","value":"Which Western Electric rule was violated (e.g., 'Point beyond 3-sigma', 'Run of 7')."},{"label":"Acknowledgment","value":"Who acknowledged, when, and their notes."}]},{"heading":"NCR Fields","items":[{"label":"NCR Number","value":"Auto-generated unique identifier."},{"label":"Type (required)","value":"Select: Internal (found in-house), Supplier (incoming material defect), Customer (customer complaint)."},{"label":"Part (required)","value":"Entity picker. The non-conforming part."},{"label":"Detection Stage (required)","value":"Select: Receiving, In Process, Final Inspection, Shipping, Customer, Audit."},{"label":"Description (required)","value":"Textarea. What the defect is and how it was found."},{"label":"Affected Quantity (required)","value":"Number. Total quantity affected."},{"label":"Defective Quantity","value":"Number, optional. How many are actually defective (may differ from affected)."},{"label":"Containment Actions","value":"Textarea, optional. Immediate actions taken to contain the defect."},{"label":"Material Cost / Labor Cost","value":"Currency, optional. Cost impact tracked for COPQ reporting."}]},{"heading":"NCR Statuses","items":[{"label":"Open","value":"NCR created, investigation not yet started."},{"label":"Under Review","value":"Quality team is evaluating the non-conformance."},{"label":"Contained","value":"Immediate containment actions completed. Awaiting disposition."},{"label":"Dispositioned","value":"Formal disposition assigned: Use As Is, Rework, Scrap, Return to Vendor, Sort & Screen, or Concession."},{"label":"Closed","value":"NCR fully resolved. Corrective actions complete if applicable."}]},{"heading":"NCR Disposition Codes","items":[{"label":"Use As Is","value":"Accept the non-conforming material without rework."},{"label":"Rework","value":"Repair or rework the material to bring it into conformance."},{"label":"Scrap","value":"Discard the non-conforming material."},{"label":"Return to Vendor","value":"Send defective material back to the supplier."},{"label":"Sort & Screen","value":"Inspect the entire lot to separate good from defective units."},{"label":"Concession","value":"Accept with customer approval or documented deviation."}]},{"heading":"CAPA Fields","items":[{"label":"CAPA Number","value":"Auto-generated unique identifier."},{"label":"Type (required)","value":"Select: Corrective (fix existing problem) or Preventive (prevent potential problem)."},{"label":"Source Type","value":"How the CAPA originated: NCR, Audit, Customer Complaint, OOC Event, Internal, Supplier."},{"label":"Title (required)","value":"Text input. Brief description of the issue being addressed."},{"label":"Problem Description (required)","value":"Textarea. Detailed description of the problem."},{"label":"Impact Description","value":"Textarea, optional. Business impact of the problem."},{"label":"Root Cause Method","value":"Select, optional: 5 Whys, Fishbone Diagram, Fault Tree, 8D."},{"label":"Root Cause Analysis","value":"Textarea, optional. Results of root cause investigation."},{"label":"Owner (required)","value":"The person responsible for driving the CAPA to completion."},{"label":"Priority","value":"Numeric priority level."},{"label":"Due Date (required)","value":"Target completion date."},{"label":"Effectiveness Check Due Date","value":"Date, optional. When to verify the corrective action is still effective."}]},{"heading":"CAPA Statuses / Phases","items":[{"label":"Identification","value":"Problem identified and documented."},{"label":"Containment","value":"Immediate actions to prevent further impact."},{"label":"Root Cause Analysis","value":"Investigating why the problem occurred."},{"label":"Corrective Action","value":"Implementing the fix or improvement."},{"label":"Verification","value":"Confirming the corrective action is effective."},{"label":"Effectiveness Check","value":"Long-term follow-up to ensure the problem does not recur."}]},{"heading":"ECO Fields","items":[{"label":"ECO Number","value":"Auto-generated unique identifier."},{"label":"Title (required)","value":"Text input. Brief description of the change."},{"label":"Description (required)","value":"Textarea. Detailed description of what is changing and why."},{"label":"Change Type (required)","value":"Select: New, Revision, Obsolescence, Cost Reduction, Quality Improvement."},{"label":"Priority (required)","value":"Select: Low, Normal, High, Critical."},{"label":"Reason for Change","value":"Textarea, optional. Why the change is needed."},{"label":"Impact Analysis","value":"Textarea, optional. Assessment of the change's impact on production, cost, and quality."},{"label":"Effective Date","value":"Date, optional. When the change takes effect."}]},{"heading":"ECO Statuses","items":[{"label":"Draft","value":"ECO created, not yet submitted for review."},{"label":"Review","value":"Submitted for review by stakeholders."},{"label":"Approved","value":"Change approved, ready for implementation."},{"label":"In Implementation","value":"Change is actively being implemented."},{"label":"Implemented","value":"Change fully implemented and verified."},{"label":"Cancelled","value":"ECO cancelled, change will not be made."}]},{"heading":"Gage Fields","items":[{"label":"Description (required)","value":"Text input. What the gage is (e.g., 'Digital Caliper 0-6\"', 'Outside Micrometer 1-2\"')."},{"label":"Gage Type","value":"Text input, optional. Category of instrument (e.g., 'Caliper', 'Micrometer', 'CMM', 'Gauge Block')."},{"label":"Manufacturer","value":"Text input, optional. Instrument manufacturer (e.g., 'Mitutoyo', 'Starrett')."},{"label":"Model","value":"Text input, optional. Manufacturer's model number."},{"label":"Serial Number","value":"Text input, optional. Unique instrument identifier."},{"label":"Calibration Interval (required)","value":"Number input (days). How often calibration is required (e.g., 365 for annual)."},{"label":"Accuracy Spec","value":"Text input, optional. Stated accuracy (e.g., '+/- 0.001\"')."},{"label":"Range Spec","value":"Text input, optional. Measurement range (e.g., '0-6 inches')."},{"label":"Resolution","value":"Text input, optional. Smallest increment (e.g., '0.0005\"')."},{"label":"Location","value":"Entity picker, optional. Storage location of the gage."},{"label":"Asset","value":"Entity picker, optional. Links gage to an asset record if applicable."},{"label":"Notes","value":"Textarea, optional. Additional information about the gage."}]},{"heading":"Gage Statuses","items":[{"label":"In Service (green)","value":"Gage is calibrated and available for use."},{"label":"Due for Calibration (yellow)","value":"Calibration interval has elapsed. Gage should not be used until recalibrated."},{"label":"Out for Calibration (blue)","value":"Gage has been sent to a calibration lab and is awaiting return."},{"label":"Out of Service (red)","value":"Gage is damaged or otherwise unusable. Requires repair."},{"label":"Retired (gray)","value":"Gage permanently removed from service."}]},{"heading":"Calibration Record Fields","items":[{"label":"Calibrated At (required)","value":"Date picker. When the calibration was performed."},{"label":"Result (required)","value":"Select: Pass (within spec), Fail (out of tolerance, cannot adjust), Adjusted (out of tolerance, corrected), Out of Tolerance (out of spec, may need investigation)."},{"label":"Lab Name","value":"Text input, optional. External calibration lab or 'In-House'."},{"label":"Certificate File","value":"File upload, optional. Calibration certificate PDF."},{"label":"Standards Used","value":"Text input, optional. Traceable standards used during calibration."},{"label":"As Found Condition","value":"Text input, optional. Gage condition before calibration."},{"label":"As Left Condition","value":"Text input, optional. Gage condition after calibration."},{"label":"Notes","value":"Textarea, optional. Additional calibration notes."}]},{"heading":"Gage Table Columns","items":[{"label":"Gage #","value":"Sortable. Auto-generated gage number. Width: 110px."},{"label":"Description","value":"Sortable. Gage description."},{"label":"Type","value":"Sortable. Gage type category. Width: 110px."},{"label":"Status","value":"Sortable, filterable (enum). Color-coded chip. Width: 130px."},{"label":"Next Cal Due","value":"Sortable, date type. Next calibration due date. Width: 110px."},{"label":"Cal Records","value":"Sortable, number type, center-aligned. Count of calibration records. Width: 90px."}]},{"heading":"Buttons and Actions","items":[{"label":"New Inspection","value":"Opens inspection creation dialog. Visible on Inspections tab. data-testid: new-inspection-btn"},{"label":"New Lot","value":"Opens lot creation dialog. Visible on Lots tab."},{"label":"New Characteristic","value":"Opens SPC characteristic creation. Visible on SPC Charts and SPC Data Entry tabs."},{"label":"New NCR","value":"Opens NCR creation dialog. Visible on NCRs tab."},{"label":"New CAPA","value":"Opens CAPA creation dialog. Visible on CAPAs tab."},{"label":"New ECO","value":"Opens ECO creation dialog. Visible on ECOs tab."},{"label":"New Gage","value":"Opens gage creation dialog. Visible on Gages tab. data-testid: new-gage-btn"},{"label":"View Traceability (tree icon)","value":"Opens lot traceability dialog showing all linked records. Available per lot row."},{"label":"Acknowledge OOC","value":"Marks an out-of-control event as reviewed. Available per OOC event."},{"label":"Create CAPA from OOC","value":"Creates a CAPA linked to the OOC event. Available per unresolved OOC event."},{"label":"Create CAPA from NCR","value":"Creates a corrective action linked to the NCR."},{"label":"Disposition NCR","value":"Opens disposition dialog to assign Use As Is, Rework, Scrap, etc."},{"label":"Record Calibration","value":"Opens calibration record dialog for the selected gage."}]},{"heading":"Scanner Integration","items":[{"label":"Inspections tab","value":"Scanning a barcode fills the inspection search field with the scanned value."},{"label":"Lots tab","value":"Scanning a barcode fills the lot search field with the scanned value."},{"label":"Scanner context","value":"Set to 'quality'. Only processes scans when the Quality page is active."}]}]}"""
        });

